import { useState } from 'react';
import type { Meta, StoryObj } from '@storybook/react-vite';
import { Collapse, type CollapseValue } from './Collapse';
import { CollapseItem } from './CollapseItem';
import { Text } from '../Text';

const meta = {
  title: 'Components/Collapse',
  component: Collapse,
  tags: ['autodocs'],
  argTypes: {
    value: { control: false },
    defaultValue: { control: false },
    onChange: { control: false },
    accordion: { control: 'boolean' },
    children: { control: false },
  },
  args: {
    accordion: false,
  },
} satisfies Meta<typeof Collapse>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Playground: Story = {
  render: (args) => (
    <div style={{ width: 420 }}>
      <Collapse {...args} defaultValue={['1']}>
        <CollapseItem name="1" title="What is Cobos UI?">
          <Text>A design system of accessible, token-driven React components.</Text>
        </CollapseItem>
        <CollapseItem name="2" title="Does it support dark mode?">
          <Text>Yes. Every component reads from the shared design tokens.</Text>
        </CollapseItem>
        <CollapseItem name="3" title="Is it tree-shakeable?">
          <Text>Components are exported individually for optimal bundling.</Text>
        </CollapseItem>
      </Collapse>
    </div>
  ),
};

export const Accordion: Story = {
  name: 'Accordion mode',
  render: () => (
    <div style={{ width: 420 }}>
      <Collapse accordion defaultValue="a">
        <CollapseItem name="a" title="Only one panel open at a time">
          <Text>Opening another panel closes this one.</Text>
        </CollapseItem>
        <CollapseItem name="b" title="Second panel">
          <Text>Accordion mode keeps the layout compact.</Text>
        </CollapseItem>
        <CollapseItem name="c" title="Third panel">
          <Text>Great for FAQs and settings.</Text>
        </CollapseItem>
      </Collapse>
    </div>
  ),
};

export const Controlled: Story = {
  render: () => {
    const [value, setValue] = useState<CollapseValue>(['general']);
    return (
      <div style={{ width: 420 }}>
        <Collapse value={value} onChange={setValue}>
          <CollapseItem name="general" title="General">
            <Text>General preferences and defaults.</Text>
          </CollapseItem>
          <CollapseItem name="privacy" title="Privacy">
            <Text>Control what data is shared.</Text>
          </CollapseItem>
          <CollapseItem name="advanced" title="Advanced (disabled)" disabled>
            <Text>Reserved for power users.</Text>
          </CollapseItem>
        </Collapse>
      </div>
    );
  },
};

import {
  createContext,
  forwardRef,
  type HTMLAttributes,
  type ReactNode,
  useCallback,
  useContext,
  useMemo,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';

export type CollapseName = string | number;
export type CollapseValue = CollapseName | CollapseName[];

export interface CollapseContextValue {
  /** Names of the currently open items. */
  activeNames: CollapseName[];
  /** Toggle an item's open state by name. */
  toggle: (name: CollapseName) => void;
}

export const CollapseContext = createContext<CollapseContextValue | null>(null);

/** Access the nearest Collapse context. Returns `null` outside a Collapse. */
export function useCollapseContext(): CollapseContextValue | null {
  return useContext(CollapseContext);
}

export interface CollapseProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'onChange' | 'value' | 'defaultValue'> {
  /** Open item name(s) (controlled). */
  value?: CollapseValue;
  /** Initial open item name(s) (uncontrolled). */
  defaultValue?: CollapseValue;
  /** Fired when the set of open items changes. */
  onChange?: (value: CollapseValue) => void;
  /** Allow only one item open at a time. */
  accordion?: boolean;
  /** `CollapseItem` elements. */
  children?: ReactNode;
}

/** Normalise a value into an array of names. */
function toArray(value: CollapseValue | undefined): CollapseName[] {
  if (value === undefined || value === null) {
    return [];
  }
  return Array.isArray(value) ? value : [value];
}

export const Collapse = forwardRef<HTMLDivElement, CollapseProps>(function Collapse(props, ref) {
  const {
    value,
    defaultValue,
    onChange,
    accordion = false,
    className,
    children,
    ...rest
  } = props;

  const ns = useNamespace('collapse');

  const isControlled = value !== undefined;
  const [internalValue, setInternalValue] = useState<CollapseName[]>(() => toArray(defaultValue));
  const activeNames = isControlled ? toArray(value) : internalValue;

  const emit = useCallback(
    (next: CollapseName[]) => {
      if (!isControlled) {
        setInternalValue(next);
      }
      // Accordion exposes a single name; otherwise the full array of open names.
      onChange?.(accordion ? (next[0] ?? '') : next);
    },
    [accordion, isControlled, onChange],
  );

  const toggle = useCallback(
    (name: CollapseName) => {
      const isOpen = activeNames.includes(name);
      if (accordion) {
        emit(isOpen ? [] : [name]);
        return;
      }
      emit(isOpen ? activeNames.filter((item) => item !== name) : [...activeNames, name]);
    },
    [accordion, activeNames, emit],
  );

  const context = useMemo<CollapseContextValue>(
    () => ({ activeNames, toggle }),
    [activeNames, toggle],
  );

  const classes = cls(ns.b(), ns.is('accordion', accordion), className);

  return (
    <CollapseContext.Provider value={context}>
      <div ref={ref} className={classes} {...rest}>
        {children}
      </div>
    </CollapseContext.Provider>
  );
});

import { forwardRef, type HTMLAttributes, type ReactNode, useId } from 'react';
import { cls, useNamespace } from '../../utils';
import { type CollapseName, useCollapseContext } from './Collapse';

export interface CollapseItemProps extends Omit<HTMLAttributes<HTMLDivElement>, 'title'> {
  /** Unique identifier, matched against the Collapse active names. */
  name: CollapseName;
  /** Header content. */
  title?: ReactNode;
  /** Disable toggling this item. */
  disabled?: boolean;
  /** Custom icon replacing the default chevron. */
  icon?: ReactNode;
  children?: ReactNode;
}

function ChevronIcon() {
  return (
    <svg viewBox="0 0 1024 1024" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
      <path
        fill="currentColor"
        d="M340.864 149.312a30.592 30.592 0 0 0 0 42.752L652.736 512 340.864 831.872a30.592 30.592 0 0 0 0 42.752 29.12 29.12 0 0 0 41.728 0L714.24 534.4a32 32 0 0 0 0-44.736L382.592 149.376a29.12 29.12 0 0 0-41.728 0z"
      />
    </svg>
  );
}

export const CollapseItem = forwardRef<HTMLDivElement, CollapseItemProps>(function CollapseItem(
  props,
  ref,
) {
  const { name, title, disabled = false, icon, className, children, ...rest } = props;

  const ns = useNamespace('collapse-item');
  const context = useCollapseContext();
  const reactId = useId();
  const headerId = `${ns.b()}-head-${reactId}`;
  const panelId = `${ns.b()}-panel-${reactId}`;

  const isActive = context?.activeNames.includes(name) ?? false;

  const handleToggle = () => {
    if (disabled) {
      return;
    }
    context?.toggle(name);
  };

  return (
    <div
      ref={ref}
      className={cls(
        ns.b(),
        ns.is('active', isActive),
        ns.is('disabled', disabled),
        className,
      )}
      {...rest}
    >
      <button
        type="button"
        id={headerId}
        className={cls(ns.e('header'), ns.is('active', isActive))}
        aria-expanded={isActive}
        aria-controls={panelId}
        aria-disabled={disabled || undefined}
        disabled={disabled}
        onClick={handleToggle}
      >
        <span className={ns.e('title')}>{title}</span>
        <span className={cls(ns.e('arrow'), ns.is('active', isActive))} aria-hidden="true">
          {icon ?? <ChevronIcon />}
        </span>
      </button>
      <div
        id={panelId}
        role="region"
        aria-labelledby={headerId}
        className={cls(ns.e('wrap'), ns.is('active', isActive))}
        hidden={!isActive}
      >
        <div className={ns.e('content')}>{children}</div>
      </div>
    </div>
  );
});

.ec-collapse {
  --ec-collapse-border-color: var(--ec-border-color-light);
  --ec-collapse-header-height: 48px;
  --ec-collapse-header-bg-color: var(--ec-fill-color-blank);
  --ec-collapse-header-text-color: var(--ec-text-color-primary);
  --ec-collapse-header-font-size: var(--ec-font-size-base);
  --ec-collapse-content-bg-color: var(--ec-fill-color-blank);
  --ec-collapse-content-text-color: var(--ec-text-color-primary);
  --ec-collapse-content-font-size: var(--ec-font-size-base);
  --ec-collapse-disabled-text-color: var(--ec-disabled-text-color);

  box-sizing: border-box;
  font-family: var(--ec-font-family);
  border-top: var(--ec-border-width) var(--ec-border-style) var(--ec-collapse-border-color);
  border-bottom: var(--ec-border-width) var(--ec-border-style) var(--ec-collapse-border-color);
}

.ec-collapse *,
.ec-collapse *::before,
.ec-collapse *::after {
  box-sizing: border-box;
}

/* ---- Item ---- */
.ec-collapse-item {
  border-bottom: var(--ec-border-width) var(--ec-border-style) var(--ec-collapse-border-color);
}

.ec-collapse-item:last-child {
  border-bottom: none;
}

/* ---- Header ---- */
.ec-collapse-item__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  width: 100%;
  box-sizing: border-box;
  height: var(--ec-collapse-header-height);
  margin: 0;
  padding: 0 12px;
  font-family: inherit;
  font-size: var(--ec-collapse-header-font-size);
  font-weight: var(--ec-font-weight-primary);
  line-height: var(--ec-collapse-header-height);
  text-align: left;
  color: var(--ec-collapse-header-text-color);
  background-color: var(--ec-collapse-header-bg-color);
  border: none;
  cursor: pointer;
  outline: none;
  appearance: none;
  transition: var(--ec-transition-color);
}

.ec-collapse-item__header:hover {
  color: var(--ec-color-primary);
}

.ec-collapse-item__header:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: -2px;
}

.ec-collapse-item__header:disabled,
.ec-collapse-item.is-disabled > .ec-collapse-item__header {
  color: var(--ec-collapse-disabled-text-color);
  cursor: not-allowed;
}

.ec-collapse-item.is-disabled > .ec-collapse-item__header:hover {
  color: var(--ec-collapse-disabled-text-color);
}

.ec-collapse-item__title {
  flex: 1;
  display: inline-flex;
  align-items: center;
}

/* ---- Arrow / chevron ---- */
.ec-collapse-item__arrow {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 1em;
  height: 1em;
  margin-left: 8px;
  font-size: var(--ec-font-size-base);
  color: var(--ec-text-color-secondary);
  transition: transform var(--ec-transition-duration) var(--ec-transition-function-ease-in-out-bezier);
  transform: rotate(0deg);
}

.ec-collapse-item__arrow svg {
  width: 1em;
  height: 1em;
}

.ec-collapse-item__arrow.is-active {
  transform: rotate(90deg);
}

/* ---- Panel ---- */
.ec-collapse-item__wrap {
  overflow: hidden;
  display: grid;
  grid-template-rows: 0fr;
  opacity: 0;
  background-color: var(--ec-collapse-content-bg-color);
  transition:
    grid-template-rows var(--ec-transition-duration) var(--ec-transition-function-ease-in-out-bezier),
    opacity var(--ec-transition-duration) var(--ec-transition-function-ease-in-out-bezier);
  will-change: grid-template-rows;
}

/* Override the `hidden` attribute's `display: none` so the panel can animate
   closed; visibility/measurement is handled by the collapsed grid row. */
.ec-collapse-item__wrap[hidden] {
  display: grid;
}

.ec-collapse-item__wrap.is-active {
  grid-template-rows: 1fr;
  opacity: 1;
}

.ec-collapse-item__content {
  overflow: hidden;
  min-height: 0;
  padding: 0 12px;
  font-size: var(--ec-collapse-content-font-size);
  line-height: 1.6;
  color: var(--ec-collapse-content-text-color);
}

.ec-collapse-item__wrap.is-active .ec-collapse-item__content {
  padding: 16px 12px 20px;
}
